    @staticmethod
    def parse_tree(problem_description):
        '''Converts a problem description into a binary tree.'''
        def helper(node_dict):
            if node_dict is None:
                return None
            node = {'value': node_dict['value']}
            node['children'] = []
            if node_dict['left'] is not None:
                node['children'].append(helper(json.loads(node_dict['left'])))
            if node_dict['right'] is not None:
                node['children'].append(helper(json.loads(node_dict['right'])))
            return node

        return helper(json.loads(problem_description))

    @staticmethod
    def generate_plan_for_node(node, words):
        if node is None:
            return ([], '')
        if node['value'] == 'Give':
            return (['Give', words[-1]], '')
        if node['value'] == 'step-by-step':
            return (['Follow each step carefully', ''], words)
        if node['value'] == 'for':
            sub_plan, _ = generate_plan_for_node(node['children'][0], words)
            return ([f'For {words[-1]}:', *sub_plan], '')
        if node['value'] == 'synthesizing':
            sub_plan, _ = generate_plan_for_node(node['children'][0], words)
            return ([f'To synthesize {words[-1]}:', *sub_plan], '')
        raise Exception(f"Unexpected node value: {node['value']}")

    @staticmethod
    def generate_solution_for_node(node, words):
        if node is None:
            return []
        if node['value'] == 'Give':
            return [f"Give {words[-1]}"]
        if node['value'] == 'step-by-step':
            return ["Step 1:", "Perform the given action.",
