            return ['For each ' + words[-1] + ':'] + solution
        if node['value'] == 'synthesizing':
            solution, _ = generate_solution_for_node(node['children'][0], words)
            return ['To synthesize ' + words[-1] + ':'] + solution
        raise Exception(f"Unexpected node value: {node['value']}")

